const cfg = $('Engagement Sequence Config').item.json;
const leadItems = $('Query Eligible Leads').all();
const now = new Date();
const tz = 'America/Los_Angeles';
const today = now.toLocaleDateString('en-CA', { timeZone: tz });
const currentHour = Number(new Intl.DateTimeFormat('en-US', {
  timeZone: tz, hour: '2-digit', hourCycle: 'h23'
}).format(now));

let estByLeadId = {};
try {
  for (const r of $('Find EST Record').all()) {
    const row = r.json;
    if (!row || !row.Id) continue;
    const leadId = String(row.Related_Lead__c || String(row.Sequence_Key__c || '').replace('_Active_v2', ''));
    if (leadId) estByLeadId[leadId] = row;
  }
} catch(e) { estByLeadId = {}; }

const excludedRaw = String(cfg.preGoLiveExcludedLeadIds || '');
const excludedIds = new Set(excludedRaw.split(',').map(s => s.trim()).filter(Boolean));
const SKIP_STATUSES = ['Unqualified', 'Do Not Contact', 'Appointment Booked', 'Follow-Up Requested'];
const MIGRATION_LEAD_ID = String(cfg.v2MigrationLeadId || 'SAMPLE_RECORD_ID');
const maxProcess = Number(cfg.maxLeadsToProcessPerPoll || cfg.batchLimit || 100);

const results = [];
for (let i = 0; i < leadItems.length; i++) {
  const lead = leadItems[i].json;
  const estRaw = estByLeadId[String(lead.Id)] || null;

  if (lead.IsConverted === true) continue;
  if (lead.Engagement_Status__c !== 'Active') continue;
  if (SKIP_STATUSES.includes(lead.Status)) continue;
  if (lead.Next_Meeting_Date__c) continue;
  if (estRaw && ['Paused', 'Stopped', 'Completed'].includes(estRaw.Sequence_Status__c)) continue;

  const rawEmail = String(lead.Email || '').trim();
  if (!rawEmail || !rawEmail.includes('@')) continue;

  if (!estRaw && excludedIds.has(String(lead.Id))) continue;

  let currentStep = estRaw ? String(estRaw.Active_Sequence_Step__c || 'Day_0') : 'Day_0';
  let lastStepSent = estRaw ? String(estRaw.Last_Sequence_Step_Sent__c || '') : '';
  let lastEmailAt = estRaw ? String(estRaw.Last_Sequence_Email_Sent_At__c || '') : '';
  let v2MigrationSeedNeeded = false;
  let v2TestResetSeedNeeded = false;
  let v2TestPlacementSeedNeeded = false;
  const isTestLead = cfg.testMode === true && String(lead.Id) === String(cfg.testLeadId || '');

  // Test mode: optional Day_0 reset (only when testResetV2Tracker=true)
  if (isTestLead && cfg.testResetV2Tracker === true) {
    currentStep = 'Day_0';
    lastStepSent = '';
    lastEmailAt = '';
    v2TestResetSeedNeeded = true;
  } else if (isTestLead && cfg.testV2PlacementSeed === true && String(cfg.testPlaceAtStep || '')) {
    const targetStep = String(cfg.testPlaceAtStep);
    const targetLastSent = String(cfg.testLastStepSent || 'Day_2');
    const targetEmailAt = String(cfg.testLastEmailAt || '2025-01-15T00:00:00.000Z');
    const estStep = estRaw ? String(estRaw.Active_Sequence_Step__c || '') : '';
    const estLastSent = estRaw ? String(estRaw.Last_Sequence_Step_Sent__c || '') : '';
    const STEP_ORDER = ['Day_0','Day_2','Day_5','Day_8','Day_12','Day_16','Day_21','Done'];
    const estIdx = STEP_ORDER.indexOf(estStep);
    const targetIdx = STEP_ORDER.indexOf(targetStep);
    const needsPlacementSeed = !estRaw
      || (estIdx >= 0 && targetIdx >= 0 && estIdx < targetIdx)
      || (estStep === targetStep && estLastSent !== targetLastSent);
    if (needsPlacementSeed) {
      currentStep = targetStep;
      lastStepSent = targetLastSent;
      lastEmailAt = targetEmailAt;
      v2TestPlacementSeedNeeded = true;
    }
  } else if (!estRaw && String(lead.Id) === MIGRATION_LEAD_ID) {
    // One-time v2 placement: lead already received old Active Day_0 + Day_3 emails (maps to v2 Day_2)
    currentStep = String(cfg.v2MigrationPlaceAtStep || 'Day_5');
    lastStepSent = String(cfg.v2MigrationLastStepSent || 'Day_2');
    lastEmailAt = String(cfg.v2MigrationLastEmailAt || '2025-01-15T00:00:00.000Z');
    v2MigrationSeedNeeded = true;
  }

  if (currentStep === 'Done') continue;

  let nextDue = estRaw ? String(estRaw.Next_Follow_Up_Date_Lead__c || today) : today;
  if (v2MigrationSeedNeeded || v2TestResetSeedNeeded || v2TestPlacementSeedNeeded) nextDue = today;
  if (isTestLead && cfg.testPlaceAtStep && currentStep === String(cfg.testPlaceAtStep)) nextDue = today;
  if (nextDue > today) continue;

  // Pacific office hours gate: 9 AM–5 PM (bypassed in test mode)
  if (!isTestLead && (currentHour < 9 || currentHour >= 17)) continue;

  const leadEmail = rawEmail;
  const sendToEmail = (cfg.testMode === true && isTestLead && String(cfg.testEmailOverride || '').trim())
    ? String(cfg.testEmailOverride).trim()
    : rawEmail;

  results.push({ json: {
    leadId: String(lead.Id),
    firstName: String(lead.FirstName || 'there'),
    lastName: String(lead.LastName || ''),
    email: sendToEmail,
    leadEmail,
    leadStatus: String(lead.Status || ''),
    engagementStatus: String(lead.Engagement_Status__c || 'Active'),
    estId: estRaw ? String(estRaw.Id) : null,
    estExists: !!estRaw,
    sequenceKey: String(lead.Id) + '_Active_v2',
    currentStep,
    nextDue,
    lastStepSent,
    lastEmailAt,
    leadOwnerId: String(lead.OwnerId || cfg.exampleOwnerId || ''),
    leadOwnerName: String((lead.Owner && lead.Owner.Name) || lead['Owner.Name'] || ''),
    leadOwnerEmail: String((lead.Owner && lead.Owner.Email) || lead['Owner.Email'] || ''),
    exampleOwnerId: String(cfg.exampleOwnerId),
    calendlyLink: String(cfg.calendlyLink),
    colleagueSignatureHtml: String(cfg.colleagueSignatureHtml || ''),
    senderCcEmail: String(cfg.senderCcEmail || ''),
    testMode: cfg.testMode === true,
    today,
    v2MigrationSeedNeeded,
    v2TestResetSeedNeeded,
    v2TestPlacementSeedNeeded
  }});
}
const capped = results.slice(0, maxProcess);
return capped.length > 0 ? capped : [{ json: { noEligibleLeads: true } }];

const ctx = $('Split In Batches — Process One Lead').item.json;
if (!ctx || !ctx.leadId) return [{ json: { noEligibleLeads: true } }];
return [{ json: { ...ctx, estExists: true, v2MigrationSeedNeeded: false, v2TestResetSeedNeeded: false, v2TestPlacementSeedNeeded: false, v2EstSeeded: true } }];

const STEP_ORDER = ['Day_0','Day_2','Day_5','Day_8','Day_12','Day_16','Day_21','Done'];
const STEP_OFFSETS = { Day_0:0, Day_2:2, Day_5:5, Day_8:8, Day_12:12, Day_16:16, Day_21:21 };
const EMAIL_STEPS = [];
const MANUAL_EMAIL_TASK_STEPS = ['Day_0','Day_2','Day_8','Day_16','Day_21'];
const CALL_TASK_STEPS = ['Day_0','Day_2','Day_5','Day_12','Day_21'];
const SMS_TASK_STEPS = ['Day_0','Day_5','Day_12','Day_21'];
const VOICEMAIL_TASK_STEPS = [];
const STATUS_REVIEW_STEPS = ['Day_21'];

const SUBJECTS = {
  Day_0: 'Thank You for Your Interest',
  Day_2: 'Following Up',
  Day_8: 'Quick Question',
  Day_16: 'Worth a Conversation?',
  Day_21: 'Closing the Loop'
};

const EMAIL_BODIES = {
  Day_0: (fn, cl) => '<p>Hi ' + fn + ',</p><p>Thank you for your interest in learning more about Example Company.</p><p>I wanted to personally reach out and introduce myself. We work with service organizations to help improve customer engagement, support positive customer outcomes, and create additional value through programs such as account reporting, customer benefits, customer education, customer rewards, and risk-management solutions.</p><p>Rather than make assumptions about what may be most relevant to your organization, I would welcome the opportunity to learn more about your organization and current priorities.</p><p>Would you be open to a brief 15-minute Discovery Call?</p><p>You can reply directly to this email or schedule a time here:<br><a href="' + cl + '">' + cl + '</a></p>',
  Day_2: (fn, cl) => '<p>Hi ' + fn + ',</p><p>I wanted to follow up on my previous email, have you had the chance to review it?</p><p>Many of the organizations we work with are focused on improving customer engagement, encouraging positive customer outcomes, creating additional value for customers, and supporting business objectives.</p><p>I would welcome the opportunity to learn more about your current programs and priorities to determine whether a conversation would make sense.</p><p>Do you have 15 minutes available next week?</p><p>You can reply directly to this email or schedule a time here:<br><a href="' + cl + '">' + cl + '</a></p>',
  Day_8: (fn) => '<p>Hi ' + fn + ',</p><p>Out of curiosity, what initially caught your attention?</p><ul><li>account reporting</li><li>customer benefits</li><li>customer rewards</li><li>customer education</li><li>protection programs</li><li>payment-performance improvement</li><li>Ancillary Revenue Opportunities</li></ul><p>Understanding your priorities will help ensure any future conversation is focused on what matters most to your organization.</p>',
  Day_16: (fn, cl) => '<p>Hi ' + fn + ',</p><p>I wanted to check in again.</p><p>Many operators are looking for ways to improve customer satisfaction, encourage positive customer outcomes, create additional business value, and strengthen owner protection without creating additional administrative burden.</p><p>Based on your interest, I thought it might make sense to have a brief conversation to see whether any of these objectives align with your current priorities.</p><p>Would you be open to a 15-minute call?</p><p>You can reply directly to this email or schedule a time here:<br><a href="' + cl + '">' + cl + '</a></p>',
  Day_21: (fn) => '<p>Hi ' + fn + ',</p><p>I have not heard back, so I will assume this is not a priority at the moment.</p><p>Rather than continue filling your inbox, I will close out my follow-up for now.</p><p>If customer benefits, account reporting, customer rewards, customer education, protection programs, or payment-performance improvement become a priority in the future, I would be happy to reconnect.</p>'
};

const EMAIL_BODIES_TEXT = {
  Day_0: (fn, cl) => 'Hi ' + fn + ',\n\nThank you for your interest in learning more about Example Company.\n\nI wanted to personally reach out and introduce myself. We work with service organizations to help improve customer engagement, support positive customer outcomes, and create additional value through programs such as account reporting, customer benefits, customer education, customer rewards, and risk-management solutions.\n\nRather than make assumptions about what may be most relevant to your organization, I would welcome the opportunity to learn more about your organization and current priorities.\n\nWould you be open to a brief 15-minute Discovery Call?\n\nYou can reply directly to this email or schedule a time here:\n' + cl,
  Day_2: (fn, cl) => 'Hi ' + fn + ',\n\nI wanted to follow up on my previous email, have you had the chance to review it?\n\nMany of the organizations we work with are focused on improving customer engagement, encouraging positive customer outcomes, creating additional value for customers, and supporting business objectives.\n\nI would welcome the opportunity to learn more about your current programs and priorities to determine whether a conversation would make sense.\n\nDo you have 15 minutes available next week?\n\nYou can reply directly to this email or schedule a time here:\n' + cl,
  Day_8: (fn) => 'Hi ' + fn + ',\n\nOut of curiosity, what initially caught your attention?\n- account reporting\n- customer benefits\n- customer rewards\n- customer education\n- protection programs\n- payment-performance improvement\n- Ancillary Revenue Opportunities\n\nUnderstanding your priorities will help ensure any future conversation is focused on what matters most to your organization.',
  Day_16: (fn, cl) => 'Hi ' + fn + ',\n\nI wanted to check in again.\n\nMany operators are looking for ways to improve customer satisfaction, encourage positive customer outcomes, create additional business value, and strengthen owner protection without creating additional administrative burden.\n\nBased on your interest, I thought it might make sense to have a brief conversation to see whether any of these objectives align with your current priorities.\n\nWould you be open to a 15-minute call?\n\nYou can reply directly to this email or schedule a time here:\n' + cl,
  Day_21: (fn) => 'Hi ' + fn + ',\n\nI have not heard back, so I will assume this is not a priority at the moment.\n\nRather than continue filling your inbox, I will close out my follow-up for now.\n\nIf customer benefits, account reporting, customer rewards, customer education, protection programs, or payment-performance improvement become a priority in the future, I would be happy to reconnect.'
};

const SMS_COPY = {
  Day_0: (fn, senderName) => 'Hi ' + fn + ', this is ' + senderName + ' with Example Company. Thank you for your interest in learning more about our programs and services. I wanted to see if there is a convenient time for a brief Discovery Call this week. Thank you.',
  Day_5: (fn, senderName) => 'Hi ' + fn + ', this is ' + senderName + ' with Example Company. I wanted to follow up and see if you had a chance to review my note. Would you be open to a brief Discovery Call to discuss your current customer engagement or account reporting priorities?',
  Day_12: (fn, senderName) => 'Hi ' + fn + ', this is ' + senderName + ' with Example Company. I wanted to check in and see if you are still interested in learning more about customer benefits, account reporting, customer rewards, customer education, or protection programs. If so, I\'d be happy to schedule a quick call.',
  Day_21: (fn, senderName) => 'Hi ' + fn + ', this is ' + senderName + ' with Example Company. I haven\'t been able to connect, so I\'ll close out my follow-up for now. If this becomes a priority later, I\'d be happy to reconnect. Thank you.'
};

const getSmsSenderName = (ctx) => {
  const ownerId = String(ctx.leadOwnerId || '');
  const ownerName = String(ctx.leadOwnerName || '').trim();
  if (ownerId === 'SAMPLE_RECORD_ID') return 'Example User';
  if (ownerId === 'SAMPLE_RECORD_ID') return 'Example Representative';
  if (ownerName) return ownerName.split(' ')[0];
  return 'Example Representative';
};

const buildSig = (sig, cl) => '<br><br>' + sig.replace('CALENDLY_PLACEHOLDER', cl);

const results = [];
for (const item of $input.all()) {
  const ctx = item.json;
  if (!ctx.leadId) continue;
  const step = ctx.currentStep;
  const stepIdx = STEP_ORDER.indexOf(step);
  const nextStep = (stepIdx >= 0 && stepIdx < STEP_ORDER.length - 1) ? STEP_ORDER[stepIdx + 1] : 'Done';
  const isLastStep = step === 'Day_21';
  const needsCallTask = CALL_TASK_STEPS.includes(step);
  const needsEmailSend = EMAIL_STEPS.includes(step);
  const needsSmsTask = SMS_TASK_STEPS.includes(step);
  const needsVoicemailTask = VOICEMAIL_TASK_STEPS.includes(step);
  const needsStatusReview = STATUS_REVIEW_STEPS.includes(step);
  const needsManualEmailTask = MANUAL_EMAIL_TASK_STEPS.includes(step);
  const daysUntilNext = (stepIdx >= 0 && STEP_ORDER[stepIdx + 1] && STEP_ORDER[stepIdx + 1] !== 'Done')
    ? (STEP_OFFSETS[STEP_ORDER[stepIdx + 1]] - STEP_OFFSETS[step]) : 0;
  const rawNextDate = new Date();
  rawNextDate.setDate(rawNextDate.getDate() + daysUntilNext);
  const rawNextDateStr = daysUntilNext > 0 ? rawNextDate.toISOString() : new Date().toISOString();
  const bodyFn = EMAIL_BODIES[step];
  const bodyContent = bodyFn ? bodyFn(ctx.firstName, ctx.calendlyLink) : null;
  const emailSubject = SUBJECTS[step] || null;
  const emailBody = (bodyContent && emailSubject) ? (bodyContent + buildSig(ctx.colleagueSignatureHtml || '', ctx.calendlyLink)) : null;
  const manualEmailTaskSubject = needsManualEmailTask ? ('Active Engagement — Send Email — Day ' + step.replace('Day_', '')) : null;
  let manualEmailTaskDescription = null;
  if (needsManualEmailTask && emailSubject) {
    const textBodyFn = EMAIL_BODIES_TEXT[step];
    const textBody = textBodyFn ? textBodyFn(ctx.firstName, ctx.calendlyLink) : null;
    if (textBody) {
      const leadName = (ctx.firstName + ' ' + ctx.lastName).trim();
      manualEmailTaskDescription = 'Lead: ' + leadName + '\nLead Email: ' + (ctx.leadEmail || ctx.email) + '\nSequence Step: ' + step + '\n\nACTION REQUIRED:\nPlease copy, personalize, and manually send the email below.\n\nEmail Subject:\n' + emailSubject + '\n\nEmail Body:\n' + textBody + '\n\nAutomation Note:\nThis task replaced the old automated email send. n8n did not send this email automatically.';
    }
  }

  const callTaskSubject = 'Active Engagement — Call Lead — ' + step.replace('_', ' ');
  const smsTaskSubject = step === 'Day_21'
    ? 'Active Engagement — Final SMS — Day 21'
    : 'Active Engagement — Send SMS — ' + step.replace('_', ' ');
  const smsSenderName = getSmsSenderName(ctx);
  const smsCopy = SMS_COPY[step] ? SMS_COPY[step](ctx.firstName, smsSenderName) : null;
  const voicemailTaskSubject = 'Active Engagement — Call Lead — Day 2';
  const statusReviewTaskSubject = 'Day 21 - Review Lead Status';
  const ccEmail = String(ctx.senderCcEmail || '');
  results.push({ json: {
    ...ctx, step, nextStep, isLastStep,
    needsCallTask, needsEmailSend, needsSmsTask, needsVoicemailTask, needsStatusReview, needsManualEmailTask,
    rawNextDateStr, emailSubject, emailBody, manualEmailTaskSubject, manualEmailTaskDescription, callTaskSubject,
    smsTaskSubject, smsCopy, voicemailTaskSubject, statusReviewTaskSubject,
    ccEmail, w11Timezone: 'America/Los_Angeles'
  }});
}
return results.length > 0 ? results : [{ json: { skip: true } }];

const ctx = $('Build Step Actions').item.json;
const lookup = $input.first()?.json || {};
if (!ctx || !ctx.leadId) return [{ json: { skip: true } }];
const stepHistoryLogged = !!(lookup && lookup.Id);
const stepHistoryEmailAt = stepHistoryLogged ? String(lookup.Last_Sequence_Email_Sent_At__c || ctx.lastEmailAt || '') : null;
return [{ json: { ...ctx, stepHistoryLogged, stepHistoryEstId: stepHistoryLogged ? String(lookup.Id) : null, stepHistoryEmailAt: stepHistoryEmailAt || null } }];

const ctx = $('Build Step Actions').item.json;
const lookup = $input.first()?.json || {};
if (!ctx || !ctx.leadId) return [{ json: { skip: true } }];
return [{ json: { ...ctx, callTaskExists: !!(lookup && lookup.Id) } }];

const ctx = $('Recover Context — Call Task Check').item.json;
if (!ctx || !ctx.leadId) return [{ json: { skip: true } }];
return [{ json: { ...ctx } }];

const ctx = $('Recover Context After Call Task').item.json;
const lookup = $input.first()?.json || {};
if (!ctx || !ctx.leadId) return [{ json: { skip: true } }];
return [{ json: { ...ctx, smsTaskExists: !!(lookup && lookup.Id) } }];

const ctx = $('Recover Context — SMS Task Check').item.json;
if (!ctx || !ctx.leadId) return [{ json: { skip: true } }];
return [{ json: { ...ctx } }];

const ctx = $('Recover Context After SMS Task').item.json;
const lookup = $input.first()?.json || {};
if (!ctx || !ctx.leadId) return [{ json: { skip: true } }];
return [{ json: { ...ctx, voicemailTaskExists: !!(lookup && lookup.Id) } }];

const ctx = $('Recover Context — Day 2 Call Task Check').item.json;
if (!ctx || !ctx.leadId) return [{ json: { skip: true } }];
return [{ json: { ...ctx } }];

const ctx = $('Recover Context After Day 2 Call Task').item.json;
const lookup = $input.first()?.json || {};
if (!ctx || !ctx.leadId) return [{ json: { skip: true } }];
return [{ json: { ...ctx, statusReviewExists: !!(lookup && lookup.Id) } }];

const ctx = $('Recover Context — Status Review Check').item.json;
if (!ctx || !ctx.leadId) return [{ json: { skip: true } }];
return [{ json: { ...ctx } }];

const ctx = $('Recover Context After Status Review').item.json;
const lookup = $input.first()?.json || {};
if (!ctx || !ctx.leadId) return [{ json: { skip: true } }];
return [{ json: { ...ctx, manualEmailTaskExists: !!(lookup && lookup.Id) } }];

const ctx = $('Recover Context — Manual Email Task Check').item.json;
if (!ctx || !ctx.leadId) return [{ json: { skip: true } }];
return [{ json: { ...ctx } }];

const ctx = $input.item.json;
if (!ctx || ctx.skip) {
  return [{ json: { ...ctx, shouldSendEmail: false, shouldAdvance: false, skipReason: ctx?.skipReason || 'skip carried forward' } }];
}

const currentStep = String(ctx.step || '');
let estLastStep = String(ctx.lastStepSent || '');
let estLastEmailAt = String(ctx.lastEmailAt || '');

try {
  const estRow = $('Find EST Record').all().find(r => r.json && String(r.json.Related_Lead__c) === String(ctx.leadId));
  if (estRow && estRow.json && estRow.json.Id) {
    estLastStep = String(estRow.json.Last_Sequence_Step_Sent__c || estLastStep);
    estLastEmailAt = String(estRow.json.Last_Sequence_Email_Sent_At__c || estLastEmailAt);
  }
} catch(e) {}

if (!ctx.needsEmailSend) {
  return [{ json: {
    ...ctx,
    shouldSendEmail: false,
    shouldAdvance: true,
    skipEmailReason: 'no email for this step',
    emailAlreadySent: false,
    emailSentThisRun: false
  }}];
}

if (estLastStep === currentStep && estLastEmailAt) {
  return [{ json: {
    ...ctx,
    shouldSendEmail: false,
    shouldAdvance: true,
    skipEmailReason: 'Email already sent for step ' + currentStep + ' at ' + estLastEmailAt,
    emailAlreadySent: true,
    emailSentThisRun: false,
    lastEmailAt: estLastEmailAt
  }}];
}

return [{ json: { ...ctx, shouldSendEmail: true, shouldAdvance: true, emailAlreadySent: false, emailSentThisRun: false } }];

let merged = { ...($('Check Email Send Dedupe').item.json || {}) };
try {
  const sent = $('Recover Context After Send').item?.json;
  if (sent && sent.leadId) merged = { ...merged, ...sent };
} catch(e) {}

if (!merged.leadId || merged.skip || merged.shouldAdvance === false) {
  return [{ json: { ...merged, skip: true, skipReason: merged.skipReason || 'cannot advance' } }];
}

const w11 = $('Call Business-Day Utility').item?.json || {};
let nextDueDateStr = null;
if (w11.isBusinessDay === true) {
  nextDueDateStr = String(w11.localDate || w11.nextBusinessDay || '').substring(0, 10);
} else {
  nextDueDateStr = String(w11.nextBusinessDay || '').substring(0, 10);
}
if (!nextDueDateStr || nextDueDateStr.length < 8) {
  return [{ json: { ...merged, skip: true, skipReason: 'Business-day utility returned no valid date' } }];
}

let emailSentAtForMainEst = merged.lastEmailAt || null;
if (merged.emailSentThisRun) {
  emailSentAtForMainEst = new Date().toISOString();
} else if (merged.needsManualEmailTask && merged.stepHistoryLogged) {
  emailSentAtForMainEst = merged.stepHistoryEmailAt || merged.lastEmailAt || null;
} else if (merged.needsManualEmailTask) {
  emailSentAtForMainEst = new Date().toISOString();
} else if (!merged.needsEmailSend) {
  emailSentAtForMainEst = merged.lastEmailAt || null;
} else if (merged.emailAlreadySent) {
  emailSentAtForMainEst = merged.lastEmailAt || null;
}

let stepHistoryEmailAt = null;
if (merged.needsEmailSend) {
  if (merged.emailSentThisRun) stepHistoryEmailAt = new Date().toISOString();
  else if (merged.emailAlreadySent) stepHistoryEmailAt = merged.lastEmailAt || null;
} else if (merged.needsManualEmailTask && merged.stepHistoryLogged) {
  stepHistoryEmailAt = merged.stepHistoryEmailAt || merged.lastEmailAt || null;
} else if (merged.needsManualEmailTask) {
  stepHistoryEmailAt = new Date().toISOString();
}

return [{ json: { ...merged, nextDueDateStr, emailSentAtForMainEst, stepHistoryEmailAt } }];
